// Sending
Navigator.push(
  context,
  MaterialPageRoute(
    builder: (context) => DetailsScreen(item: myItem),
  ),
);

// Receiving
class DetailsScreen extends StatelessWidget {
  final Item item;
  DetailsScreen({required this.item});
  ...
}

// With named routes
Navigator.pushNamed(
  context,
  '/details',
  arguments: myItem,
);

// Receiving
final args = ModalRoute.of(context)!.settings.arguments as Item;
